<template><div class="page-container"><el-card><template #header><span>产品管理</span><el-button type="primary" size="small" style="float:right">添加产品</el-button></template><el-form :inline="true"><el-form-item label="状态"><el-select v-model="f.status" clearable><el-option label="启用" value="ACTIVE"/><el-option label="停用" value="INACTIVE"/></el-select></el-form-item><el-form-item label="搜索"><el-input v-model="f.search" placeholder="产品名称/SKU" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="product_no" label="产品编号" width="120"/><el-table-column prop="name" label="产品名称" width="200"/><el-table-column prop="cost_price" label="成本价" width="100"/><el-table-column prop="weight" label="重量(kg)" width="100"/><el-table-column prop="status" label="状态" width="80"/><el-table-column prop="created_at" label="创建时间" width="160"/><el-table-column label="操作" width="150" fixed="right"><template #default="{ row }"><el-button size="small">编辑</el-button><el-button size="small" type="danger">删除</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { productApi } from '@/api/productSys'
const f = reactive({ status: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await productApi.list({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
onMounted(load)
</script>
